package com.example.sharehandler

import android.content.Intent
import android.graphics.Bitmap
import android.net.Uri
import android.os.Bundle
import android.util.Log
import androidx.appcompat.app.AppCompatActivity
import java.io.File
import java.io.FileOutputStream
import java.util.UUID

class ShareHandlerActivity : AppCompatActivity() {
    private val TAG = "ShareHandlerActivity"
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        val action = intent.action
        val type = intent.type
        
        if (Intent.ACTION_SEND == action && type != null) {
            handleSendIntent()
        } else {
            Log.w(TAG, "Unhandled intent received")
            finish()
        }
    }
    
    private fun handleSendIntent() {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        val sharedImage = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        
        if (sharedText != null) {
            processSharedText(sharedText)
        }
        
        if (sharedImage != null) {
            processSharedImage(sharedImage)
        }
        
        finish()
    }
    
    private fun processSharedText(text: String) {
        Log.d(TAG, "Received shared text: $text")
        
        if (isValidUrl(text)) {
            Log.d(TAG, "Valid URL detected: $text")
            // Process URL
        } else {
            Log.d(TAG, "Text content: $text")
            // Process text content
        }
    }
    
    private fun processSharedImage(imageUri: Uri) {
        try {
            val bitmap = contentResolver.openInputStream(imageUri)?.use {
                android.graphics.BitmapFactory.decodeStream(it)
            }
            
            if (bitmap != null) {
                Log.d(TAG, "Received shared image with dimensions: ${bitmap.width}x${bitmap.height}")
                // Process image
                saveImageToCache(bitmap)
            } else {
                Log.w(TAG, "Failed to decode image from URI: $imageUri")
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error processing shared image", e)
        }
    }
    
    private fun saveImageToCache(bitmap: Bitmap): String {
        val fileName = "shared_image_${UUID.randomUUID()}.png"
        val file = File(cacheDir, fileName)
        
        FileOutputStream(file).use { out ->
            bitmap.compress(Bitmap.CompressFormat.PNG, 100, out)
        }
        
        return file.absolutePath
    }
    
    private fun isValidUrl(url: String): Boolean {
        return try {
            val uri = Uri.parse(url)
            uri.scheme != null && uri.authority != null
        } catch (e: Exception) {
            false
        }
    }
}